    rss_r4 = float(np.sum((resid - z_res_4 @ beta_r4) ** 2))

    df_num_4 = k
    df_den_4 = n_obs - z_unres_4.shape[1]
    if df_den_4 > 0:
        f4 = ((rss_r4 - rss_u4) / df_num_4) / (rss_u4 / df_den_4)
        p4 = 1.0 - stats.f.cdf(f4, df_num_4, df_den_4)
