    beta_r3 = np.linalg.lstsq(z_res_3, resid, rcond=None)[0]
    rss_u3 = float(np.sum((resid - z_unres_3 @ beta_u3) ** 2))
    rss_r3 = float(np.sum((resid - z_res_3 @ beta_r3) ** 2))

    df_num_3 = k
