    # H02: beta_1 = 0 (given beta_2 = beta_3 = 0)
    z_unres_2 = np.hstack([z0, z1])
    z_res_2 = z0

    beta_u2 = np.linalg.lstsq(z_unres_2, resid, rcond=None)[0]
